PODS=$(sudo k3s kubectl get pods -l app=laravel --field-selector=status.phase=Running -o custom-columns=":metadata.name" --no-headers); for POD in $PODS; do echo "Patching $POD..."; sudo k3s kubectl cp /tmp/index.blade.php default/$POD:/app/resources/views/marketplace/index.blade.php -c laravel; sudo k3s kubectl cp /tmp/detail.blade.php default/$POD:/app/resources/views/marketplace/detail.blade.php -c laravel; sudo k3s kubectl cp /tmp/app.blade.php default/$POD:/app/resources/views/user/layout/app.blade.php -c laravel; done;
